def extract_with_context(client, document_text):
    # Step 1: Identify relevant sections
    section_tool = {
        "name": "identify_sections",
        "input_schema": {"type": "object", "properties": {"sections": {"type": "array", "items": {"type": "string"}}}}

    section_msg = client.messages.create(
        model="claude-3-5-sonnet-20240620",
        tools=[section_tool],
        messages=[{"role": "user", "content": f"Identify invoice sections in: {document_text}"}]
    )

    # Step 2: Extract from identified sections
    extract_msg = client.messages.create(
        model="claude-3-5-sonnet-20240620",
        tools=[extract_invoice_tool],
        messages=[
            {"role": "user", "content": f"Extract from sections: {section_msg.content[0].input}"},
            {"role": "assistant", "content": section_msg.content}
        ]
    )
    return extract_msg.content[0].input

result = extract_with_context(client, "Invoice header... line items... total")

