import { verify, SchemaValidator } from 'vex-sdk';

import { z } from 'zod';
const InvoiceSchema = z.object({
  vendor: z.string().min(1),
  date: z.string().regex(/^\d{4}-\d{2}-\d{2}$/),
  total: z.number().positive()
});

// After parallel tool calls
const toolResults = [
  { name: 'extract_header', input: { vendor: 'Acme', date: '2024-01-15' } },
  { name: 'extract_totals', input: { total: 1250 } }
];

const mergedResult = toolResults.reduce((acc, tool) => ({ ...acc, ...tool.input }), {});

const verification = await verify({
  data: mergedResult,
  validators: [
    new SchemaValidator(InvoiceSchema),
    { type: 'field_accuracy', field: 'total', minValue: 0 },
    { type: 'type_consistency', schema: InvoiceSchema },
    { type: 'completeness', requiredFields: ['vendor', 'date', 'total'] }
  ],
  riskProfile: 'medium'
});

if (verification.status === 'pass') {
  console.log('Verified extraction:', verification.data);
} else {
  console.error('Verification failed:', verification.errors);
}
